+    if (cmp == 0) {
+        item.?.ob_refcnt += 1;
+        return item;
+    }
+
+    // Replace root with item
+    top.ob_refcnt += 1;
+    item.?.ob_refcnt += 1;
+    _ = list.PyList_SetItem(heap, 0, item.?);
+    _ = siftup(heap, 0);
+
+    return top;
+}
