+    const len = PySequence_Size(o);
+    if (len < 0) return -1;
+
+    var count: isize = 0;
+    var i: isize = 0;
+    while (i < len) : (i += 1) {
+        const item = PySequence_GetItem(o, i) orelse continue;
+        const eq = PyObject_RichCompareBool(item, value.?, Py_EQ);
+        if (eq == 1) count += 1;
+    }
+    return count;
+}
