+/// Check if object is true
+pub export fn PyObject_IsTrue(op: ?*cpython.PyObject) c_int {
+    if (op == null) return 0;
+
+    const obj = op.?;
+
+    // None is always false
+    if (obj == &_Py_NoneStruct) {
