+/// Memory domain identifiers
+pub const PYMEM_DOMAIN_RAW: c_uint = 0;
+pub const PYMEM_DOMAIN_MEM: c_uint = 1;
+pub const PYMEM_DOMAIN_OBJ: c_uint = 2;
