+pub export fn PyUnicodeWriter_WriteStr(writer: ?*PyUnicodeWriter, str: ?*cpython.PyObject) c_int {
+    if (writer == null) return -1;
+    return _PyUnicodeWriter_WriteStr(writer.?, str);
