+
+/// Public API: Write a character
+pub export fn PyUnicodeWriter_WriteChar(writer: ?*PyUnicodeWriter, ch: u32) c_int {
+    if (writer == null) return -1;
+    return _PyUnicodeWriter_WriteChar(writer.?, ch);
