+
+/// Public API: Write repr of object
+pub export fn PyUnicodeWriter_WriteRepr(writer: ?*PyUnicodeWriter, obj: ?*cpython.PyObject) c_int {
+    if (writer == null) return -1;
+    if (obj == null) return -1;
