+/// Returns 1 for Unicode characters having the Numeric property
+pub export fn _PyUnicode_IsNumeric(ch: u32) c_int {
+    const ctype = gettyperecord(ch);
+    return if ((ctype.flags & NUMERIC_MASK) != 0) 1 else 0;
